import React, { createContext, useContext, useState, useEffect } from 'react';
import { Product, Service, Customer, Staff, Transaction, UserRole, MembershipTier, Branch, Device, Appointment, Expense, BodyAnalysis, AppNotification, Drink, LoyaltyRule, ServicePackage, DrinkOrder, DietDay, ChatMessage, ActiveCall } from '../types';
import { db, isDemoMode } from '../firebaseConfig';
import { 
  collection, 
  onSnapshot, 
  addDoc, 
  updateDoc, 
  deleteDoc, 
  doc, 
  setDoc, 
  writeBatch,
  query,
  orderBy,
  limit,
  where,
  startAfter,
  getDocs
} from 'firebase/firestore';

interface SalonState {
  branches: Branch[];
  devices: Device[];
  products: Product[];
  services: Service[];
  customers: Customer[];
  staff: Staff[];
  transactions: Transaction[];
  expenses: Expense[];
  appointments: Appointment[];
  notifications: AppNotification[];
  drinks: Drink[];
  loyaltyRules: LoyaltyRule[];
  loyaltyRate: number;
  tierLimits: Record<string, number>;
  servicePackages: ServicePackage[];
  drinkOrders: DrinkOrder[];
  adminKey: string;
  receptionistKey: string;
  staffKey: string;
  kvkkText: string;
  currentRole: UserRole;
  activeCall: ActiveCall | null; // NEW
  setRole: (role: UserRole) => void;
  isAuthenticated: boolean;
  isOnline: boolean;
  login: (key: string) => boolean;
  logout: () => void;
  updateSystemKeys: (admin: string, receptionist: string, staff: string) => void;
  updateKvkkText: (text: string) => void;
  updateLoyaltySettings: (rate: number, rules: LoyaltyRule[], limits: Record<string, number>) => void;
  completeSale: (customerId: string, staffId: string, items: any[], paymentType: any, rating?: number) => void;
  checkServicePerformance: () => void;
  exportData: () => void;
  importData: (file: File) => Promise<{ success: boolean; message: string }>;
  addAppointment: (app: Appointment) => void;
  updateAppointmentStatus: (id: string, status: 'PENDING' | 'COMPLETED' | 'CANCELLED') => void;
  deleteData: (id: string, type: string) => void;
  addProduct: (product: Product) => void;
  updateProduct: (product: Product) => void;
  addService: (service: Service) => void;
  updateService: (service: Service) => void;
  addStaff: (staff: Staff) => void;
  updateStaff: (staff: Staff) => void;
  addCustomer: (customer: Customer) => void;
  updateCustomer: (customer: Customer) => void;
  addExpense: (expense: Expense) => void;
  addDevice: (device: Device) => void;
  updateDevice: (device: Device) => void;
  addBodyAnalysis: (customerId: string, analysis: BodyAnalysis) => void;
  useSession: (customerId: string, packageId: string) => void;
  resetToDefaults: () => void;
  addNotification: (notif: Omit<AppNotification, 'id' | 'timestamp' | 'isRead'>) => void;
  markNotifRead: (id: string) => void;
  addDrink: (drink: Drink) => void;
  updateDrink: (drink: Drink) => void;
  addPackage: (pkg: ServicePackage) => void;
  updatePackage: (pkg: ServicePackage) => void;
  addDrinkOrder: (order: Omit<DrinkOrder, 'id' | 'timestamp' | 'status'>) => void;
  updateDrinkOrderStatus: (id: string, status: DrinkOrder['status']) => void;
  // NEW DIET ACTIONS
  updateDietPlan: (customerId: string, plan: DietDay[]) => void;
  sendDietMessage: (customerId: string, message: Omit<ChatMessage, 'id' | 'timestamp' | 'isRead'>) => void;
  // CALL ACTIONS
  initiateCall: (customerId: string, type: 'VIDEO' | 'AUDIO') => void;
  answerCall: () => void;
  endCall: () => void;
  // SCALABILITY ACTIONS
  searchCustomers: (queryStr: string) => Promise<void>;
  loadMoreCustomers: () => Promise<void>;
  hasMoreCustomers: boolean;
  isLoadingCustomers: boolean;
}

const SalonContext = createContext<SalonState | undefined>(undefined);

const DEFAULT_KVKK = `Değerli Misafirimiz, L'YSF Life Center olarak kişisel verilerinizin güvenliği hususuna azami hassasiyet göstermekteyiz...`;

// Helper to save to local storage in Demo Mode
const saveLocal = (key: string, data: any) => {
  localStorage.setItem(`LYSF_DEMO_${key}`, JSON.stringify(data));
};

const getLocal = (key: string) => {
  const d = localStorage.getItem(`LYSF_DEMO_${key}`);
  return d ? JSON.parse(d) : [];
};

export const SalonProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(localStorage.getItem('LYSF_AUTH') === 'true');
  const [currentRole, setRole] = useState<UserRole>((localStorage.getItem('LYSF_ROLE') as UserRole) || UserRole.STAFF);
  const [isOnline, setIsOnline] = useState<boolean>(navigator.onLine);

  // Data States
  const [branches, setBranches] = useState<Branch[]>([]);
  const [devices, setDevices] = useState<Device[]>([]);
  const [products, setProducts] = useState<Product[]>([]);
  const [services, setServices] = useState<Service[]>([]);
  const [customers, setCustomers] = useState<Customer[]>([]);
  const [staff, setStaff] = useState<Staff[]>([]);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [expenses, setExpenses] = useState<Expense[]>([]);
  const [appointments, setAppointments] = useState<Appointment[]>([]);
  const [notifications, setNotifications] = useState<AppNotification[]>([]);
  const [drinks, setDrinks] = useState<Drink[]>([]);
  const [servicePackages, setServicePackages] = useState<ServicePackage[]>([]);
  const [drinkOrders, setDrinkOrders] = useState<DrinkOrder[]>([]);

  // Global Call State
  const [activeCall, setActiveCall] = useState<ActiveCall | null>(null);

  // Pagination States for Scalability
  const [lastCustomerDoc, setLastCustomerDoc] = useState<any>(null);
  const [hasMoreCustomers, setHasMoreCustomers] = useState(true);
  const [isLoadingCustomers, setIsLoadingCustomers] = useState(false);

  // System Settings State
  const [loyaltyRules, setLoyaltyRules] = useState<LoyaltyRule[]>([
    { id: 'lr1', minPoints: 10000, reward: 'Ücretsiz Yüz Maskesi Hediyesi!' },
    { id: 'lr2', minPoints: 25000, reward: 'Vücut Analizi & Diyetisyen Randevusu Hediye!' }
  ]);
  const [loyaltyRate, setLoyaltyRate] = useState<number>(5);
  const [tierLimits, setTierLimits] = useState<Record<string, number>>({
    SILVER: 5000, GOLD: 15000, PLATINUM: 30000, BLACK_VIP: 50000
  });
  const [adminKey, setAdminKey] = useState<string>('ADMIN_LYSF');
  const [receptionistKey, setReceptionistKey] = useState<string>('RECEP_LYSF');
  const [staffKey, setStaffKey] = useState<string>('EXPERT_LYSF');
  const [kvkkText, setKvkkText] = useState<string>(DEFAULT_KVKK);

  // --- FIREBASE REALTIME LISTENERS / DEMO LOAD ---
  useEffect(() => {
    // Helper to filter out soft-deleted items (active === false)
    const filterActive = (list: any[]) => list.filter((item: any) => item.active !== false);
    const filterActiveSnap = (snap: any, mapper: (d: any) => any) => 
        snap.docs.map(mapper).filter((item: any) => item.active !== false);

    if (isDemoMode) {
        // DEMO MODE: Load from localStorage
        setProducts(filterActive(getLocal('products')));
        setServices(filterActive(getLocal('services')));
        setCustomers(filterActive(getLocal('customers')));
        setStaff(filterActive(getLocal('staff')));
        setExpenses(filterActive(getLocal('expenses')));
        setAppointments(filterActive(getLocal('appointments')));
        setBranches(filterActive(getLocal('branches')));
        setDevices(filterActive(getLocal('devices')));
        setDrinks(filterActive(getLocal('drinks')));
        setServicePackages(filterActive(getLocal('servicePackages')));
        setTransactions(filterActive(getLocal('transactions')).sort((a: any, b: any) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime()));
        setNotifications(filterActive(getLocal('notifications')).sort((a: any, b: any) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime()));
        setDrinkOrders(filterActive(getLocal('drinkOrders')));

        // System Config
        const sys = getLocal('system_config');
        if (sys && !Array.isArray(sys)) { 
            setAdminKey(sys.adminKey || 'ADMIN_LYSF');
            setReceptionistKey(sys.receptionistKey || 'RECEP_LYSF');
            setStaffKey(sys.staffKey || 'EXPERT_LYSF');
            setKvkkText(sys.kvkkText || DEFAULT_KVKK);
            setLoyaltyRate(sys.loyaltyRate || 5);
            setTierLimits(sys.tierLimits || { SILVER: 5000, GOLD: 15000, PLATINUM: 30000, BLACK_VIP: 50000 });
            setLoyaltyRules((sys.loyaltyRules || []).filter((r: any) => r.active !== false));
        }
        return;
    }

    // FIREBASE MODE - REALTIME LISTENERS
    // Note: Customers are NOT loaded via realtime listener for scalability (1M records issue).
    // Instead we load them initially via pagination logic below.

    const unsubProducts = onSnapshot(collection(db, 'products'), (snap) => setProducts(filterActiveSnap(snap, d => ({...d.data(), id: d.id} as Product))));
    const unsubServices = onSnapshot(collection(db, 'services'), (snap) => setServices(filterActiveSnap(snap, d => ({...d.data(), id: d.id} as Service))));
    const unsubStaff = onSnapshot(collection(db, 'staff'), (snap) => setStaff(filterActiveSnap(snap, d => ({...d.data(), id: d.id} as Staff))));
    const unsubExpenses = onSnapshot(collection(db, 'expenses'), (snap) => setExpenses(filterActiveSnap(snap, d => ({...d.data(), id: d.id} as Expense))));
    const unsubAppointments = onSnapshot(collection(db, 'appointments'), (snap) => setAppointments(filterActiveSnap(snap, d => ({...d.data(), id: d.id} as Appointment))));
    const unsubBranches = onSnapshot(collection(db, 'branches'), (snap) => setBranches(filterActiveSnap(snap, d => ({...d.data(), id: d.id} as Branch))));
    const unsubDevices = onSnapshot(collection(db, 'devices'), (snap) => setDevices(filterActiveSnap(snap, d => ({...d.data(), id: d.id} as Device))));
    const unsubDrinks = onSnapshot(collection(db, 'drinks'), (snap) => setDrinks(filterActiveSnap(snap, d => ({...d.data(), id: d.id} as Drink))));
    const unsubPackages = onSnapshot(collection(db, 'servicePackages'), (snap) => setServicePackages(filterActiveSnap(snap, d => ({...d.data(), id: d.id} as ServicePackage))));

    // Transactions - LIMIT 50 for Performance
    const unsubTransactions = onSnapshot(
        query(collection(db, 'transactions'), orderBy('timestamp', 'desc'), limit(50)), 
        (snap) => {
            const txs = snap.docs.map(d => ({...d.data(), id: d.id} as Transaction));
            setTransactions(txs.filter(t => t.active !== false));
        }
    );

    // Initial Customer Load (First 50) - Scalability Fix
    const initialCustomerLoad = async () => {
        setIsLoadingCustomers(true);
        // By default sort by name or creation date. Assuming no 'createdAt', using simple query.
        // For production 1M records, you should have an index on 'fullName'.
        const q = query(collection(db, 'customers'), limit(50)); 
        const snap = await getDocs(q);
        const loadedCustomers = snap.docs.map(d => ({...d.data(), id: d.id} as Customer)).filter(c => c.active !== false);
        setCustomers(loadedCustomers);
        setLastCustomerDoc(snap.docs[snap.docs.length - 1]);
        setHasMoreCustomers(snap.docs.length === 50);
        setIsLoadingCustomers(false);
    };
    initialCustomerLoad();

    // Notifications (Son 50)
    const unsubNotifications = onSnapshot(
        query(collection(db, 'notifications'), orderBy('timestamp', 'desc'), limit(50)), 
        (snap) => {
            const notifs = snap.docs.map(d => ({...d.data(), id: d.id} as AppNotification));
            setNotifications(notifs.filter(n => n.active !== false));
        }
    );

    // Drink Orders (Son 50)
    const unsubOrders = onSnapshot(
        query(collection(db, 'drinkOrders'), orderBy('timestamp', 'desc'), limit(50)), 
        (snap) => {
            const orders = snap.docs.map(d => ({...d.data(), id: d.id} as DrinkOrder));
            setDrinkOrders(orders.filter(o => o.active !== false));
        }
    );

    // Call Signaling (Using Firestore for signaling in Cloud Mode, or local state in Demo)
    if (!isDemoMode) {
        // ... (Real implementation would use a 'calls' collection listener)
    }

    // Sistem Ayarları
    const systemConfigRef = doc(db, 'system', 'config');
    const unsubSettings = onSnapshot(systemConfigRef, (docSnap) => {
        if (docSnap.exists()) {
            const data = docSnap.data();
            setAdminKey(data.adminKey || 'ADMIN_LYSF');
            setReceptionistKey(data.receptionistKey || 'RECEP_LYSF');
            setStaffKey(data.staffKey || 'EXPERT_LYSF');
            setKvkkText(data.kvkkText || DEFAULT_KVKK);
            setLoyaltyRate(data.loyaltyRate || 5);
            setTierLimits(data.tierLimits || { SILVER: 5000, GOLD: 15000, PLATINUM: 30000, BLACK_VIP: 50000 });
            setLoyaltyRules((data.loyaltyRules || []).filter((r: any) => r.active !== false));
        } else {
            setDoc(systemConfigRef, {
                adminKey: 'ADMIN_LYSF',
                receptionistKey: 'RECEP_LYSF',
                staffKey: 'EXPERT_LYSF',
                kvkkText: DEFAULT_KVKK,
                loyaltyRate: 5,
                tierLimits: { SILVER: 5000, GOLD: 15000, PLATINUM: 30000, BLACK_VIP: 50000 },
                loyaltyRules: [
                    { id: 'lr1', minPoints: 10000, reward: 'Ücretsiz Yüz Maskesi Hediyesi!', active: true },
                    { id: 'lr2', minPoints: 25000, reward: 'Vücut Analizi & Diyetisyen Randevusu Hediye!', active: true }
                ]
            });
        }
    });

    const handleOnline = () => setIsOnline(true);
    const handleOffline = () => setIsOnline(false);
    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);

    return () => {
      unsubProducts(); unsubServices(); unsubStaff(); unsubExpenses(); unsubAppointments();
      unsubBranches(); unsubDevices(); unsubDrinks(); unsubPackages(); unsubTransactions(); unsubNotifications(); unsubOrders(); unsubSettings();
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, []);

  // --- CALL ACTIONS ---
  const initiateCall = (customerId: string, type: 'VIDEO' | 'AUDIO') => {
      const call: ActiveCall = {
          customerId,
          hostName: 'Yönetim',
          type,
          status: 'RINGING',
          timestamp: new Date().toISOString()
      };
      setActiveCall(call);
      // In a real app, this would push to Firebase 'calls' collection
  };

  const answerCall = () => {
      if (activeCall) {
          setActiveCall({ ...activeCall, status: 'CONNECTED' });
      }
  };

  const endCall = () => {
      setActiveCall(null);
  };

  // --- SCALABILITY METHODS (FIREBASE ONLY) ---

  const searchCustomers = async (queryStr: string) => {
      if (isDemoMode) return; // Demo mode uses local filtering in component

      setIsLoadingCustomers(true);
      if (!queryStr) {
          // Reset to initial load if search is cleared
          const q = query(collection(db, 'customers'), limit(50));
          const snap = await getDocs(q);
          const loaded = snap.docs.map(d => ({...d.data(), id: d.id} as Customer)).filter(c => c.active !== false);
          setCustomers(loaded);
          setLastCustomerDoc(snap.docs[snap.docs.length - 1]);
          setHasMoreCustomers(snap.docs.length === 50);
      } else {
          // Server-side search (requires index on 'fullName')
          // Using a simple prefix search logic here.
          const q = query(
              collection(db, 'customers'), 
              where('fullName', '>=', queryStr),
              where('fullName', '<=', queryStr + '\uf8ff'),
              limit(50)
          );
          const snap = await getDocs(q);
          const loaded = snap.docs.map(d => ({...d.data(), id: d.id} as Customer)).filter(c => c.active !== false);
          setCustomers(loaded);
          // Search results generally don't support standard pagination easily without complex logic, 
          // so we disable 'load more' for search results in this simple implementation or implement a cursor based on search sort.
          setHasMoreCustomers(false); 
      }
      setIsLoadingCustomers(false);
  };

  const loadMoreCustomers = async () => {
      if (isDemoMode || !hasMoreCustomers || !lastCustomerDoc) return;

      setIsLoadingCustomers(true);
      const q = query(collection(db, 'customers'), startAfter(lastCustomerDoc), limit(50));
      const snap = await getDocs(q);

      if (!snap.empty) {
          const newCustomers = snap.docs.map(d => ({...d.data(), id: d.id} as Customer)).filter(c => c.active !== false);
          setCustomers(prev => [...prev, ...newCustomers]);
          setLastCustomerDoc(snap.docs[snap.docs.length - 1]);
          setHasMoreCustomers(snap.docs.length === 50);
      } else {
          setHasMoreCustomers(false);
      }
      setIsLoadingCustomers(false);
  };

  // --- GENERIC CRUD HELPERS ---
  const handleAdd = (collectionName: string, item: any, stateSetter: any, currentList: any[]) => {
      if (isDemoMode) {
          const newItem = { ...item, id: item.id || Date.now().toString(), active: true };
          const newList = [...currentList, newItem];
          stateSetter(newList);
          saveLocal(collectionName, newList);
      } else {
          const { id, ...data } = item;
          // For customers, we just fire and forget, since the list is managed by pagination/search
          if (collectionName === 'customers') {
              addDoc(collection(db, collectionName), { ...data, active: true });
              // Optimistically add to current list if it's small
              if (customers.length < 50) setCustomers(prev => [{...item, id: 'temp-id', active: true}, ...prev]);
          } else {
              addDoc(collection(db, collectionName), { ...data, active: true });
          }
      }
  };

  const handleUpdate = (collectionName: string, item: any, stateSetter: any, currentList: any[]) => {
      if (isDemoMode) {
          const newList = currentList.map(i => i.id === item.id ? { ...i, ...item } : i);
          stateSetter(newList);
          saveLocal(collectionName, newList);
      } else {
          updateDoc(doc(db, collectionName, item.id), { ...item });
          // For customers, update local state manually to reflect changes immediately without re-fetch
          if (collectionName === 'customers') {
              setCustomers(prev => prev.map(c => c.id === item.id ? { ...c, ...item } : c));
          }
      }
  };

  // --- ACTIONS ---

  const addNotification = async (notif: Omit<AppNotification, 'id' | 'timestamp' | 'isRead'>) => {
    const exists = notifications.some(n => !n.isRead && n.title === notif.title && n.type === notif.type && n.message === notif.message);
    if(exists) return;

    const newNotif: AppNotification = {
      ...notif,
      id: Date.now().toString(),
      timestamp: new Date().toLocaleTimeString('tr-TR'),
      isRead: false,
      active: true
    };
    if (isDemoMode) {
        const newList = [newNotif, ...notifications];
        setNotifications(newList);
        saveLocal('notifications', newList);
    } else {
        await addDoc(collection(db, 'notifications'), newNotif);
    }
  };

  const markNotifRead = async (id: string) => {
     if (isDemoMode) {
         const newList = notifications.map(n => n.id === id ? { ...n, isRead: true } : n);
         setNotifications(newList);
         saveLocal('notifications', newList);
     } else {
         await updateDoc(doc(db, 'notifications', id), { isRead: true });
     }
  };

  // --- DIET ACTIONS ---
  const updateDietPlan = async (customerId: string, plan: DietDay[]) => {
      if (isDemoMode) {
          const newList = customers.map(c => c.id === customerId ? { ...c, dietPlan: plan } : c);
          setCustomers(newList);
          saveLocal('customers', newList);
      } else {
          await updateDoc(doc(db, 'customers', customerId), { dietPlan: plan });
          setCustomers(prev => prev.map(c => c.id === customerId ? { ...c, dietPlan: plan } : c));
      }
  };

  const sendDietMessage = async (customerId: string, message: Omit<ChatMessage, 'id' | 'timestamp' | 'isRead'>) => {
      const customer = customers.find(c => c.id === customerId);

      const newMessage: ChatMessage = {
          ...message,
          id: Date.now().toString(),
          timestamp: new Date().toISOString(),
          isRead: false
      };

      if (isDemoMode) {
          if (!customer) return;
          const updatedHistory = [...(customer.dietChatHistory || []), newMessage];
          const newList = customers.map(c => c.id === customerId ? { ...c, dietChatHistory: updatedHistory } : c);
          setCustomers(newList);
          saveLocal('customers', newList);
      } else {
          if (customer) {
              const updatedHistory = [...(customer.dietChatHistory || []), newMessage];
              await updateDoc(doc(db, 'customers', customerId), { dietChatHistory: updatedHistory });
              setCustomers(prev => prev.map(c => c.id === customerId ? { ...c, dietChatHistory: updatedHistory } : c));
          }
      }

      if (message.sender === 'CUSTOMER') {
          addNotification({
              type: 'DIET_CHAT',
              title: `Diyet Mesajı: ${customer?.fullName || 'Danışan'}`,
              message: message.type === 'IMAGE' ? 'Bir fotoğraf gönderdi.' : (message.content.length > 30 ? message.content.substring(0,30)+'...' : message.content)
          });
      }
  };

  // --- DRINK ORDER ACTIONS ---
  const addDrinkOrder = async (order: Omit<DrinkOrder, 'id' | 'timestamp' | 'status'>) => {
    const existing = drinkOrders.find(o => o.customerId === order.customerId && o.status !== 'DELIVERED');
    if (existing) return;

    const newOrder: DrinkOrder = {
        ...order,
        id: Date.now().toString(),
        status: 'RECEIVED',
        timestamp: new Date().toLocaleTimeString('tr-TR'),
        active: true
    };
    if (isDemoMode) {
        const newList = [...drinkOrders, newOrder];
        setDrinkOrders(newList);
        saveLocal('drinkOrders', newList);
    } else {
        await addDoc(collection(db, 'drinkOrders'), newOrder);
    }
    addNotification({
        type: 'ORDER',
        title: 'Yeni İçecek Siparişi',
        message: `${order.customerName} - ${order.drinkName}`
    });
  };

  const updateDrinkOrderStatus = async (id: string, status: DrinkOrder['status']) => {
      if (isDemoMode) {
          const newList = drinkOrders.map(o => o.id === id ? { ...o, status } : o);
          setDrinkOrders(newList);
          saveLocal('drinkOrders', newList);
      } else {
          await updateDoc(doc(db, 'drinkOrders', id), { status });
      }
  };

  const completeSale = async (customerId: string, staffId: string, items: any[], paymentType: any, rating?: number) => {
    let totalGross = 0;
    const stockAlerts: string[] = [];

    // Calculate new stock and alerts
    const updatedProducts = [...products];
    items.forEach(item => {
      totalGross += item.price * (item.quantity || 1);
      if (item.type === 'SERVICE' || !item.type) {
        const service = services.find(s => s.id === item.id);
        if (service && service.linkedProductId) {
          const productIndex = updatedProducts.findIndex(p => p.id === service.linkedProductId);
          if (productIndex > -1) {
            const product = { ...updatedProducts[productIndex] };
            const amountToDeduct = (product.usagePerSession || 0) * (item.quantity || 1);
            let newCurrent = product.currentUnitRemaining - amountToDeduct;
            let newStock = product.stock;
            while (newCurrent <= 0 && newStock > 0) { newStock -= 1; newCurrent += product.volumePerUnit; }
            if (newStock === 0 && newCurrent < 0) newCurrent = 0;
            product.stock = newStock;
            product.currentUnitRemaining = newCurrent;
            updatedProducts[productIndex] = product;
            if (newStock <= product.lowStockThreshold) stockAlerts.push(`${product.name} (Kalan: ${newStock})`);
          }
        }
      }
    });

    // Handle Customer Update - In Firebase Mode, we must be careful if customer isn't in local state
    // We will assume for sales, the customer IS in local state because they were selected from a list.
    const customerIndex = customers.findIndex(c => c.id === customerId);
    let updatedCustomer = customerIndex > -1 ? { ...customers[customerIndex] } : null;

    if (updatedCustomer) {
        const earnedPoints = Math.floor(totalGross * (loyaltyRate / 100));
        const newTotalSpent = (updatedCustomer.dna.totalSpent || 0) + totalGross;
        const newPoints = (updatedCustomer.dna.loyaltyPuan || 0) + earnedPoints;
        let newTier = updatedCustomer.tier;
        if (newTotalSpent >= tierLimits.BLACK_VIP && newTier !== MembershipTier.BLACK_VIP) { newTier = MembershipTier.BLACK_VIP; }
        else if (newTotalSpent >= tierLimits.PLATINUM && newTier !== MembershipTier.PLATINUM && newTier !== MembershipTier.BLACK_VIP) { newTier = MembershipTier.PLATINUM; }
        else if (newTotalSpent >= tierLimits.GOLD && newTier !== MembershipTier.GOLD && newTier !== MembershipTier.PLATINUM && newTier !== MembershipTier.BLACK_VIP) { newTier = MembershipTier.GOLD; }
        else if (newTotalSpent >= tierLimits.SILVER && newTier === MembershipTier.BRONZE) { newTier = MembershipTier.SILVER; }

        updatedCustomer.tier = newTier;
        updatedCustomer.dna.loyaltyPuan = newPoints;
        updatedCustomer.dna.totalSpent = newTotalSpent;
    }

    const staffIndex = staff.findIndex(s => s.id === staffId);
    let updatedStaff = staffIndex > -1 ? { ...staff[staffIndex] } : null;
    if (updatedStaff) {
        updatedStaff.totalSales += totalGross;
    }

    const newTx: Transaction = {
        id: Date.now().toString(),
        branchId: 'b1', customerId, staffId, items, grossRevenue: totalGross, netProfit: totalGross * 0.4, paymentType, rating, timestamp: new Date().toISOString(), active: true
    };

    if (isDemoMode) {
        // Apply updates to local state and storage
        setProducts(updatedProducts); saveLocal('products', updatedProducts);
        if(updatedCustomer) { 
            const newCustomers = [...customers]; newCustomers[customerIndex] = updatedCustomer; 
            setCustomers(newCustomers); saveLocal('customers', newCustomers);
        }
        if(updatedStaff) {
            const newStaff = [...staff]; newStaff[staffIndex] = updatedStaff;
            setStaff(newStaff); saveLocal('staff', newStaff);
        }
        const newTransactions = [newTx, ...transactions];
        setTransactions(newTransactions); saveLocal('transactions', newTransactions);
    } else {
        // Firebase Batch
        const batch = writeBatch(db);
        updatedProducts.forEach(p => { 
            if (p !== products.find(op => op.id === p.id)) batch.update(doc(db, 'products', p.id), { stock: p.stock, currentUnitRemaining: p.currentUnitRemaining }); 
        });
        if (updatedCustomer) {
            batch.update(doc(db, 'customers', customerId), { tier: updatedCustomer.tier, "dna.loyaltyPuan": updatedCustomer.dna.loyaltyPuan, "dna.totalSpent": updatedCustomer.dna.totalSpent });
            // Optimistically update local state
            setCustomers(prev => prev.map(c => c.id === customerId ? updatedCustomer! : c));
        }
        if (updatedStaff) {
            batch.update(doc(db, 'staff', staffId), { totalSales: updatedStaff.totalSales });
        }
        batch.set(doc(collection(db, 'transactions')), newTx);
        await batch.commit();
    }

    stockAlerts.forEach(msg => { addNotification({ type: 'LOW_STOCK', title: 'Kritik Stok Uyarısı', message: `${msg} seviyesine indi.` }); });
  };

  const checkServicePerformance = () => {
    const thirtyDaysAgo = new Date(); thirtyDaysAgo.setDate(thirtyDaysAgo.getDate() - 30);
    const recentTransactions = transactions.filter(t => new Date(t.timestamp) >= thirtyDaysAgo);
    const serviceCounts: Record<string, number> = {};
    services.forEach(s => serviceCounts[s.id] = 0);
    recentTransactions.forEach(t => { t.items.forEach(item => { if (serviceCounts[item.id] !== undefined) serviceCounts[item.id] += (item.quantity || 1); }); });
    services.forEach(service => { if (serviceCounts[service.id] < 3) { addNotification({ type: 'PERFORMANCE_ALERT', title: 'Düşük Talep Uyarısı', message: `${service.name} hizmeti son 30 günde az tercih edildi.` }); } });
  };

  // --- SOFT DELETE IMPLEMENTATION ---
  const deleteData = async (id: string, type: string) => {
    const collectionMap: any = { 
        'PRODUCT': 'products', 
        'CUSTOMER': 'customers', 
        'SERVICE': 'services', 
        'STAFF': 'staff', 
        'EXPENSE': 'expenses', 
        'DEVICE': 'devices', 
        'NOTIFICATION': 'notifications', 
        'DRINK': 'drinks', 
        'LOYALTY_RULE': 'loyaltyRules', 
        'PACKAGE': 'servicePackages', 
        'APPOINTMENT': 'appointments' 
    };

    if (collectionMap[type]) {
        if (isDemoMode) {
            const col = collectionMap[type];
            const currentList = getLocal(col);
            const newList = currentList.map((item: any) => item.id === id ? { ...item, active: false } : item);
            saveLocal(col, newList);
            if(type === 'PRODUCT') setProducts(products.filter(i => i.id !== id));
            if(type === 'SERVICE') setServices(services.filter(i => i.id !== id));
            if(type === 'CUSTOMER') setCustomers(customers.filter(i => i.id !== id));
            if(type === 'STAFF') setStaff(staff.filter(i => i.id !== id));
            if(type === 'EXPENSE') setExpenses(expenses.filter(i => i.id !== id));
            if(type === 'APPOINTMENT') setAppointments(appointments.filter(i => i.id !== id));
            if(type === 'DRINK') setDrinks(drinks.filter(i => i.id !== id));
            if(type === 'PACKAGE') setServicePackages(servicePackages.filter(i => i.id !== id));
            if(type === 'NOTIFICATION') setNotifications(notifications.filter(i => i.id !== id));
        } else {
            await updateDoc(doc(db, collectionMap[type], id), { active: false });
            if (type === 'CUSTOMER') setCustomers(prev => prev.filter(c => c.id !== id));
        }
    }

    if (type === 'LOYALTY_RULE') { 
        const newRules = loyaltyRules.map(r => r.id === id ? { ...r, active: false } : r); 
        if (isDemoMode) {
            setLoyaltyRules(newRules.filter(r => r.active !== false));
            const sys = getLocal('system_config') || {};
            sys.loyaltyRules = newRules;
            saveLocal('system_config', sys);
        } else {
            await updateDoc(doc(db, 'system', 'config'), { loyaltyRules: newRules }); 
        }
    }
  };

  // --- CRUD WRAPPERS ---
  const addProduct = (p: Product) => handleAdd('products', p, setProducts, products);
  const updateProduct = (p: Product) => handleUpdate('products', p, setProducts, products);
  const addService = (s: Service) => handleAdd('services', s, setServices, services);
  const updateService = (s: Service) => handleUpdate('services', s, setServices, services);
  const addStaff = (s: Staff) => handleAdd('staff', s, setStaff, staff);
  const updateStaff = (s: Staff) => handleUpdate('staff', s, setStaff, staff);
  const addCustomer = (c: Customer) => handleAdd('customers', c, setCustomers, customers);
  const updateCustomer = (c: Customer) => handleUpdate('customers', c, setCustomers, customers);
  const addExpense = (e: Expense) => handleAdd('expenses', e, setExpenses, expenses);
  const addDevice = (d: Device) => handleAdd('devices', d, setDevices, devices);
  const updateDevice = (d: Device) => handleUpdate('devices', d, setDevices, devices);
  const addDrink = (d: Drink) => handleAdd('drinks', d, setDrinks, drinks);
  const updateDrink = (d: Drink) => handleUpdate('drinks', d, setDrinks, drinks);
  const addPackage = (p: ServicePackage) => handleAdd('servicePackages', p, setServicePackages, servicePackages);
  const updatePackage = (p: ServicePackage) => handleUpdate('servicePackages', p, setServicePackages, servicePackages);
  const addAppointment = (app: Appointment) => handleAdd('appointments', app, setAppointments, appointments);
  const updateAppointmentStatus = async (id: string, status: any) => {
      if (isDemoMode) {
          const newList = appointments.map(a => a.id === id ? { ...a, status } : a);
          setAppointments(newList);
          saveLocal('appointments', newList);
      } else {
          await updateDoc(doc(db, 'appointments', id), { status });
      }
  };

  // Update System Settings
  const saveSystemConfig = (data: any) => {
      if (isDemoMode) {
          const current = getLocal('system_config') || {};
          const newData = { ...current, ...data };
          saveLocal('system_config', newData);
      } else {
          updateDoc(doc(db, 'system', 'config'), data);
      }
  }

  const updateLoyaltySettings = (rate: number, rules: LoyaltyRule[], limits: Record<string, number>) => { 
      setLoyaltyRate(rate); setLoyaltyRules(rules); setTierLimits(limits);
      saveSystemConfig({ loyaltyRate: rate, loyaltyRules: rules, tierLimits: limits });
  };
  const updateSystemKeys = (admin: string, receptionist: string, staff: string) => { 
      setAdminKey(admin); setReceptionistKey(receptionist); setStaffKey(staff);
      saveSystemConfig({ adminKey: admin, receptionistKey: receptionist, staffKey: staff });
  };
  const updateKvkkText = (text: string) => { 
      setKvkkText(text);
      saveSystemConfig({ kvkkText: text });
  };

  const addBodyAnalysis = async (customerId: string, analysis: BodyAnalysis) => { 
      const customer = customers.find(c => c.id === customerId); 
      if(customer) { 
          const newAnalysis = [...(customer.bodyAnalysis || []), analysis]; 
          if(isDemoMode) {
              const newList = customers.map(c => c.id === customerId ? { ...c, bodyAnalysis: newAnalysis } : c);
              setCustomers(newList); saveLocal('customers', newList);
          } else {
              await updateDoc(doc(db, 'customers', customerId), { bodyAnalysis: newAnalysis }); 
              setCustomers(prev => prev.map(c => c.id === customerId ? { ...c, bodyAnalysis: newAnalysis } : c));
          }
      } 
  };

  const useSession = async (customerId: string, packageId: string) => { 
      const customer = customers.find(c => c.id === customerId); 
      if(customer) { 
          const newPackages = customer.packages.map(p => p.id === packageId ? { ...p, remainingSessions: Math.max(0, p.remainingSessions - 1) } : p); 
          if(isDemoMode) {
              const newList = customers.map(c => c.id === customerId ? { ...c, packages: newPackages } : c);
              setCustomers(newList); saveLocal('customers', newList);
          } else {
              await updateDoc(doc(db, 'customers', customerId), { packages: newPackages }); 
              setCustomers(prev => prev.map(c => c.id === customerId ? { ...c, packages: newPackages } : c));
          }
      } 
  };

  const exportData = () => {
    const data = { products, services, customers, staff, transactions, expenses, appointments, branches, devices, adminKey, receptionistKey, staffKey, kvkkText, notifications, drinks, loyaltyRules, loyaltyRate, tierLimits, servicePackages };
    const blob = new Blob([JSON.stringify(data)], { type: 'application/json' });
    const a = document.createElement('a'); a.href = URL.createObjectURL(blob); a.download = `LYSF_OS_FULL_BACKUP_${new Date().toLocaleDateString()}.json`; a.click();
  };

  const importData = async (file: File) => {
    try {
      const text = await file.text(); const d = JSON.parse(text); 

      if (isDemoMode) {
          if(d.products) { setProducts(d.products); saveLocal('products', d.products); }
          if(d.customers) { setCustomers(d.customers); saveLocal('customers', d.customers); }
          // ... import others ...
          return { success: true, message: "Veriler yerel depolamaya aktarıldı." };
      } else {
          const batch = writeBatch(db);
          if(d.products) d.products.forEach((p: any) => { const ref = doc(collection(db, 'products')); batch.set(ref, { ...p, active: true }); });
          if(d.customers) d.customers.forEach((c: any) => { const ref = doc(collection(db, 'customers')); batch.set(ref, { ...c, active: true }); });
          await batch.commit(); return { success: true, message: "Veriler buluta aktarıldı." };
      }
    } catch (e) { return { success: false, message: "Dosya hatası." }; }
  };

  const resetToDefaults = async () => { 
      if (confirm("DİKKAT: Veritabanındaki tüm veriler silinecek! Onaylıyor musunuz?")) { 
          localStorage.removeItem('LYSF_AUTH'); 
          localStorage.removeItem('LYSF_ROLE'); 
          if(isDemoMode) {
              localStorage.clear(); // Clear all demo data
          }
          window.location.reload(); 
      } 
  };

  const login = (key: string) => {
    if (key === adminKey) { setRole(UserRole.MANAGER); setIsAuthenticated(true); localStorage.setItem('LYSF_AUTH', 'true'); localStorage.setItem('LYSF_ROLE', UserRole.MANAGER); return true; }
    if (key === receptionistKey) { setRole(UserRole.RECEPTIONIST); setIsAuthenticated(true); localStorage.setItem('LYSF_AUTH', 'true'); localStorage.setItem('LYSF_ROLE', UserRole.RECEPTIONIST); return true; }
    if (key === staffKey) { setRole(UserRole.EXPERT); setIsAuthenticated(true); localStorage.setItem('LYSF_AUTH', 'true'); localStorage.setItem('LYSF_ROLE', UserRole.EXPERT); return true; }
    return false;
  };
  const logout = () => { setIsAuthenticated(false); localStorage.removeItem('LYSF_AUTH'); localStorage.removeItem('LYSF_ROLE'); };

  return (
    <SalonContext.Provider value={{
      branches, devices, products, services, customers, staff, transactions, expenses, appointments, notifications, drinks, loyaltyRules, loyaltyRate, tierLimits, servicePackages, drinkOrders, adminKey, receptionistKey, staffKey, kvkkText, currentRole, setRole, activeCall,
      isAuthenticated, isOnline, login, logout, updateSystemKeys, updateKvkkText, updateLoyaltySettings, completeSale, checkServicePerformance, exportData, importData,
      addAppointment, updateAppointmentStatus, deleteData, addProduct, updateProduct,
      addService, updateService, addStaff, updateStaff, addCustomer, updateCustomer, addExpense, addDevice, updateDevice,
      addBodyAnalysis, useSession, resetToDefaults, addNotification, markNotifRead, addDrink, updateDrink,
      addPackage, updatePackage, addDrinkOrder, updateDrinkOrderStatus,
      updateDietPlan, sendDietMessage, initiateCall, answerCall, endCall,
      // SCALABILITY EXPORTS
      searchCustomers, loadMoreCustomers, hasMoreCustomers, isLoadingCustomers
    }}>
      {children}
    </SalonContext.Provider>
  );
};

export const useSalon = () => {
  const context = useContext(SalonContext);
  if (!context) throw new Error("useSalon error");
  return context;
};

