                <div>
                  <h2 className="text-xl font-black uppercase italic">{isPanicMode ? 'KİLİTLİ' : 'GÜVENLİ'}</h2>
                  <p className="text-[10px] font-bold opacity-60 uppercase tracking-widest">PANİK KİLİDİ</p>
