import React, { useState, useRef, useEffect, useMemo } from 'react';
import { useSalon } from '../store/SalonContext';
import { Customer, MembershipTier } from '../types';
import { 
  Lock, ArrowRight, Apple, Droplets, Image as ImageIcon, Send, 
  Search, User, LogOut, ChevronLeft, CreditCard, History, Star,
  CalendarDays, ShoppingBag, Activity, Mic, Square, Play, Pause, 
  Video, Phone, Headphones, TrendingUp, ChevronRight, UserPlus, CheckCircle2
} from 'lucide-react';
import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, LineChart, Line, Legend } from 'recharts';

export const CustomerPortal: React.FC = () => {
  const { customers, updateCustomer, sendDietMessage, transactions, generateHealthReport, activeCall, initiateCall, addNotification } = useSalon();

  // Login / Selection State
  const [activeCustomer, setActiveCustomer] = useState<Customer | null>(null);
  const [searchPhone, setSearchPhone] = useState('');

  // Registration State
  const [isRegistering, setIsRegistering] = useState(false);
  const [regName, setRegName] = useState('');
  const [regPhone, setRegPhone] = useState('');

  // Portal Navigation
  const [currentTab, setCurrentTab] = useState<'HOME' | 'DIET' | 'ANALYSIS' | 'APPOINTMENTS' | 'WALLET'>('HOME');

  // Diet Specific States
  const [dietUnlocked, setDietUnlocked] = useState(false);
  const [dietPasswordInput, setDietPasswordInput] = useState('');
  const [dietChatInput, setDietChatInput] = useState('');
  const dietChatScrollRef = useRef<HTMLDivElement>(null);

  // Audio Recording States
  const [isRecording, setIsRecording] = useState(false);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const [audioChunks, setAudioChunks] = useState<Blob[]>([]);
  const [playingAudioId, setPlayingAudioId] = useState<string | null>(null);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  // Analysis Audio Report States
  const [isGeneratingReport, setIsGeneratingReport] = useState(false);
  const [isPlayingReport, setIsPlayingReport] = useState(false);

  // Theme Helpers
  const getTierTheme = (tier: string) => {
    switch (tier) {
      case 'BLACK_VIP': return { bg: 'bg-slate-900', text: 'text-slate-900', subText: 'text-slate-500', border: 'border-slate-900', gradient: 'from-slate-800 to-black', accent: 'text-[#E0AA3E]' };
      case 'PLATINUM': return { bg: 'bg-indigo-600', text: 'text-indigo-600', subText: 'text-indigo-400', border: 'border-indigo-600', gradient: 'from-indigo-500 to-indigo-900', accent: 'text-indigo-500' };
      case 'GOLD': return { bg: 'bg-amber-500', text: 'text-amber-600', subText: 'text-amber-500', border: 'border-amber-500', gradient: 'from-amber-400 to-amber-600', accent: 'text-amber-500' };
      default: return { bg: 'bg-emerald-500', text: 'text-emerald-600', subText: 'text-emerald-500', border: 'border-emerald-500', gradient: 'from-emerald-400 to-emerald-600', accent: 'text-emerald-500' };
    }
  };

  const tierTheme = activeCustomer ? getTierTheme(activeCustomer.tier) : getTierTheme('BRONZE');

  // Sync activeCustomer with context
  useEffect(() => {
    if (activeCustomer) {
      const freshData = customers.find(c => c.id === activeCustomer.id);
      if (freshData) setActiveCustomer(freshData);
    }
  }, [customers]);

  useEffect(() => {
    if (dietChatScrollRef.current) {
      dietChatScrollRef.current.scrollTop = dietChatScrollRef.current.scrollHeight;
    }
  }, [currentTab, activeCustomer?.dietChatHistory]);

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const found = customers.find(c => c.phone.includes(searchPhone) || c.fullName.toLowerCase().includes(searchPhone.toLowerCase()));
    if (found) {
      setActiveCustomer(found);
      setDietUnlocked(false);
    } else {
      alert('Müşteri bulunamadı. Lütfen kayıt olun veya bilgilerinizi kontrol edin.');
    }
  };

  const handleRegister = (e: React.FormEvent) => {
      e.preventDefault();
      if (!regName || !regPhone) return alert("Lütfen tüm alanları doldurun.");

      const exists = customers.find(c => c.phone === regPhone);
      if (exists) return alert("Bu numara ile zaten bir kayıt var. Lütfen giriş yapın.");

      addNotification({
          type: 'REGISTRATION_REQUEST',
          title: 'Tablet Kayıt İsteği',
          message: `${regName} kayıt olmak istiyor. Onaylayarak sisteme ekleyebilirsiniz.`,
          data: { name: regName, phone: regPhone }
      });

      alert("Kaydınız alındı! Lütfen danışmadaki arkadaşımıza isminizi iletiniz, onay sonrası giriş yapabilirsiniz.");
      setIsRegistering(false);
      setRegName('');
      setRegPhone('');
  };

  const handleDietUnlock = () => {
    if (activeCustomer && activeCustomer.dietPassword === dietPasswordInput) {
      setDietUnlocked(true);
      setDietPasswordInput('');
    } else {
      alert('Hatalı şifre!');
    }
  };

  const handleSendDietChat = () => {
    if (!activeCustomer || !dietChatInput.trim()) return;

    sendDietMessage(activeCustomer.id, {
        sender: 'CUSTOMER',
        content: dietChatInput,
        type: 'TEXT'
    });
    setDietChatInput('');
  };

  const handleDietImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
      if (e.target.files && e.target.files[0] && activeCustomer) {
          const file = e.target.files[0];
          const reader = new FileReader();
          reader.onloadend = () => {
            sendDietMessage(activeCustomer.id, {
                sender: 'CUSTOMER',
                content: reader.result as string,
                type: 'IMAGE'
            });
          };
          reader.readAsDataURL(file);
      }
  };

  // --- AUDIO RECORDING LOGIC ---
  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      mediaRecorderRef.current = new MediaRecorder(stream);
      mediaRecorderRef.current.ondataavailable = (event) => {
        if (event.data.size > 0) {
          setAudioChunks((prev) => [...prev, event.data]);
        }
      };
      mediaRecorderRef.current.start();
      setIsRecording(true);
    } catch (err) {
      console.error("Mic error:", err);
      alert("Mikrofon erişimi sağlanamadı.");
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current) {
      mediaRecorderRef.current.stop();
      mediaRecorderRef.current.onstop = () => {
        const audioBlob = new Blob(audioChunks, { type: 'audio/webm' });
        const reader = new FileReader();
        reader.readAsDataURL(audioBlob);
        reader.onloadend = () => {
            const base64 = reader.result as string;
            if (activeCustomer) {
                sendDietMessage(activeCustomer.id, {
                    sender: 'CUSTOMER',
                    content: base64,
                    type: 'AUDIO'
                });
            }
            setAudioChunks([]);
        };
        // Stop all tracks
        mediaRecorderRef.current?.stream.getTracks().forEach(track => track.stop());
      };
      setIsRecording(false);
    }
  };

  const toggleAudioPlay = (msgId: string, content: string) => {
      if (playingAudioId === msgId) {
          audioRef.current?.pause();
          setPlayingAudioId(null);
      } else {
          if (audioRef.current) {
              audioRef.current.src = content;
              audioRef.current.play();
              setPlayingAudioId(msgId);
              audioRef.current.onended = () => setPlayingAudioId(null);
          }
      }
  };

  // --- VIDEO CALL LOGIC ---
  const handleJoinCall = () => {
      if(activeCall && activeCall.customerId === activeCustomer?.id) {
          alert("Görüşmeye bağlanılıyor...");
          // In a real app, this would open the WebRTC connection
      } else {
          // Request a call
          if(activeCustomer) initiateCall(activeCustomer.id, 'VIDEO');
          alert("Diyetisyene çağrı isteği gönderildi.");
      }
  };

  // --- ANALYSIS REPORT LOGIC ---
  const handleGenerateReport = async () => {
      if (!activeCustomer) return;
      setIsGeneratingReport(true);
      await generateHealthReport(activeCustomer.id);
      setIsGeneratingReport(false);
      setIsPlayingReport(true);
      // Simulate playing report
      setTimeout(() => setIsPlayingReport(false), 5000); 
  };

  if (!activeCustomer) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center p-10 bg-slate-50">
        <div className="max-w-md w-full text-center space-y-8 animate-in zoom-in-95">
           <div className="w-24 h-24 bg-slate-900 rounded-[2.5rem] flex items-center justify-center mx-auto text-white shadow-2xl">
              <User size={48} />
           </div>

           {!isRegistering ? (
               // LOGIN FORM
               <>
                   <div>
                     <h1 className="text-3xl font-black text-slate-900 italic">Müşteri Girişi</h1>
                     <p className="text-slate-400 font-bold">Lütfen telefon numaranızı girin.</p>
                   </div>
                   <form onSubmit={handleLogin} className="relative">
                     <input 
                       type="text" 
                       value={searchPhone}
                       onChange={e => setSearchPhone(e.target.value)}
                       placeholder="5XX..."
                       className="w-full p-6 rounded-[2rem] border-2 border-slate-200 outline-none text-2xl font-black text-center focus:border-slate-900 transition-all"
                     />
                     <button type="submit" className="absolute right-3 top-3 bottom-3 aspect-square bg-slate-900 text-white rounded-[1.5rem] flex items-center justify-center hover:bg-black transition-all">
                        <ArrowRight size={24} />
                     </button>
                   </form>
                   <button onClick={() => setIsRegistering(true)} className="text-slate-400 font-black uppercase tracking-widest text-xs hover:text-rose-500 transition-colors flex items-center justify-center gap-2">
                       <UserPlus size={16}/> Aramıza Katılın (Yeni Kayıt)
                   </button>
               </>
           ) : (
               // REGISTRATION FORM
               <>
                   <div>
                     <h1 className="text-3xl font-black text-slate-900 italic">Yeni Üye Kaydı</h1>
