                                               <button onClick={startRecording} className="p-3 bg-slate-100 text-slate-500 rounded-full hover:bg-rose-500 hover:text-white shadow-sm transition-all active:scale-95">
                                                   <Mic size={18}/>
                                               </button>
                                           )}
                                       </>
                                   )}
                               </div>
                           </div>
                       </div>
                   </div>
