  Video, Phone, Headphones, TrendingUp, Sparkles, Flower2, ScanFace
} from 'lucide-react';
import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';

export const CustomerPortal: React.FC = () => {
  const { customers, sendDietMessage, transactions, generateHealthReport, activeCall, initiateCall } = useSalon();

  // Login / Selection State
  const [activeCustomer, setActiveCustomer] = useState<Customer | null>(null);
  const [searchPhone, setSearchPhone] = useState('');

  // Portal Navigation
  const [currentTab, setCurrentTab] = useState<'HOME' | 'DIET' | 'ANALYSIS' | 'APPOINTMENTS' | 'WALLET'>('HOME');

  // Diet Specific States
  const [dietUnlocked, setDietUnlocked] = useState(false);
  const [dietPasswordInput, setDietPasswordInput] = useState('');
  const [dietChatInput, setDietChatInput] = useState('');
  const dietChatScrollRef = useRef<HTMLDivElement>(null);

  // Audio Recording States
  const [isRecording, setIsRecording] = useState(false);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const [audioChunks, setAudioChunks] = useState<Blob[]>([]);
  const [playingAudioId, setPlayingAudioId] = useState<string | null>(null);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  // Analysis Audio Report States
  const [isGeneratingReport, setIsGeneratingReport] = useState(false);
  const [isPlayingReport, setIsPlayingReport] = useState(false);

  // Theme Helpers
  const getTierTheme = (tier: string) => {
    switch (tier) {
      case 'BLACK_VIP': return { bg: 'bg-slate-900', text: 'text-slate-900', subText: 'text-slate-500', border: 'border-slate-900', gradient: 'from-slate-800 to-black', accent: 'text-[#E0AA3E]' };
      case 'PLATINUM': return { bg: 'bg-indigo-600', text: 'text-indigo-600', subText: 'text-indigo-400', border: 'border-indigo-600', gradient: 'from-indigo-500 to-indigo-900', accent: 'text-indigo-500' };
      case 'GOLD': return { bg: 'bg-amber-500', text: 'text-amber-600', subText: 'text-amber-500', border: 'border-amber-500', gradient: 'from-amber-400 to-amber-600', accent: 'text-amber-500' };
      default: return { bg: 'bg-emerald-500', text: 'text-emerald-600', subText: 'text-emerald-500', border: 'border-emerald-500', gradient: 'from-emerald-400 to-emerald-600', accent: 'text-emerald-500' };
    }
  };

  const tierTheme = activeCustomer ? getTierTheme(activeCustomer.tier) : getTierTheme('BRONZE');

  // Sync activeCustomer with context
  useEffect(() => {
    if (activeCustomer) {
      const freshData = customers.find(c => c.id === activeCustomer.id);
      if (freshData) setActiveCustomer(freshData);
    }
  }, [customers]);

  useEffect(() => {
    if (dietChatScrollRef.current) {
      dietChatScrollRef.current.scrollTop = dietChatScrollRef.current.scrollHeight;
    }
  }, [currentTab, activeCustomer?.dietChatHistory]);

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const found = customers.find(c => c.phone.includes(searchPhone) || c.fullName.toLowerCase().includes(searchPhone.toLowerCase()));
    if (found) {
      setActiveCustomer(found);
      setDietUnlocked(false);
    } else {
      alert('Müşteri bulunamadı. Lütfen bilgilerinizi kontrol edin.');
    }
  };

  const handleDietUnlock = () => {
    if (activeCustomer && activeCustomer.dietPassword === dietPasswordInput) {
      setDietUnlocked(true);
      setDietPasswordInput('');
    } else {
      alert('Hatalı şifre!');
    }
  };

  const handleSendDietChat = () => {
    if (!activeCustomer || !dietChatInput.trim()) return;

    sendDietMessage(activeCustomer.id, {
        sender: 'CUSTOMER',
        content: dietChatInput,
        type: 'TEXT'
    });
    setDietChatInput('');
  };

  const handleDietImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
      if (e.target.files && e.target.files[0] && activeCustomer) {
          const file = e.target.files[0];
          const reader = new FileReader();
          reader.onloadend = () => {
            sendDietMessage(activeCustomer.id, {
                sender: 'CUSTOMER',
                content: reader.result as string,
                type: 'IMAGE'
            });
          };
          reader.readAsDataURL(file);
      }
  };

  // --- AUDIO RECORDING LOGIC ---
  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      mediaRecorderRef.current = new MediaRecorder(stream);
      mediaRecorderRef.current.ondataavailable = (event) => {
        if (event.data.size > 0) {
          setAudioChunks((prev) => [...prev, event.data]);
        }
      };
      mediaRecorderRef.current.start();
      setIsRecording(true);
    } catch (err) {
      console.error("Mic error:", err);
      alert("Mikrofon erişimi sağlanamadı.");
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current) {
      mediaRecorderRef.current.stop();
      mediaRecorderRef.current.onstop = () => {
        const audioBlob = new Blob(audioChunks, { type: 'audio/webm' });
        const reader = new FileReader();
        reader.readAsDataURL(audioBlob);
        reader.onloadend = () => {
            const base64 = reader.result as string;
            if (activeCustomer) {
                sendDietMessage(activeCustomer.id, {
                    sender: 'CUSTOMER',
                    content: base64,
                    type: 'AUDIO'
                });
            }
            setAudioChunks([]);
        };
        // Stop all tracks
        mediaRecorderRef.current?.stream.getTracks().forEach(track => track.stop());
      };
      setIsRecording(false);
    }
  };

  const toggleAudioPlay = (msgId: string, content: string) => {
      if (playingAudioId === msgId) {
          audioRef.current?.pause();
          setPlayingAudioId(null);
      } else {
          if (audioRef.current) {
              audioRef.current.src = content;
              audioRef.current.play();
              setPlayingAudioId(msgId);
              audioRef.current.onended = () => setPlayingAudioId(null);
          }
      }
  };

  // --- VIDEO CALL LOGIC ---
  const handleJoinCall = () => {
      if(activeCall && activeCall.customerId === activeCustomer?.id) {
          alert("Görüşmeye bağlanılıyor...");
      } else {
          if(activeCustomer) initiateCall(activeCustomer.id, 'VIDEO');
          alert("Diyetisyene çağrı isteği gönderildi.");
      }
  };

  // --- ANALYSIS REPORT LOGIC ---
  const handleGenerateReport = async () => {
      if (!activeCustomer) return;
      setIsGeneratingReport(true);
      await generateHealthReport(activeCustomer.id);
      setIsGeneratingReport(false);
      setIsPlayingReport(true);
      setTimeout(() => setIsPlayingReport(false), 5000); 
  };

  if (!activeCustomer) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center p-10 bg-slate-50 relative overflow-hidden">
        {/* Dekoratif Arka Plan Elemanları (Yüz, Çiçek vb.) */}
        <div className="absolute top-20 right-20 text-rose-200 opacity-50 animate-pulse"><Flower2 size={120} /></div>
        <div className="absolute bottom-20 left-20 text-indigo-200 opacity-50"><ScanFace size={120} /></div>
        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[500px] h-[500px] bg-gradient-to-r from-rose-100 to-indigo-100 rounded-full blur-[100px] opacity-50 -z-10"></div>

        <div className="max-w-md w-full text-center space-y-10 animate-in zoom-in-95 relative z-10">
           <div className="w-32 h-32 bg-white rounded-[3rem] flex items-center justify-center mx-auto text-rose-500 shadow-2xl border-4 border-white rotate-3">
              <Sparkles size={64} />
           </div>

           <div>
             <h1 className="text-4xl font-black text-slate-900 italic tracking-tighter mb-2">Hoşgeldiniz</h1>
             <p className="text-slate-400 font-bold uppercase tracking-widest text-xs">L'YSF Life Center Müşteri Paneli</p>
           </div>

           <form onSubmit={handleLogin} className="relative group">
             <input 
               type="text" 
               value={searchPhone}
               onChange={e => setSearchPhone(e.target.value)}
               placeholder="Telefon Numaranız"
               className="w-full p-8 rounded-[3rem] border-2 border-white bg-white/80 backdrop-blur-xl outline-none text-2xl font-black text-center focus:border-rose-500 shadow-xl transition-all placeholder:text-slate-300 text-slate-900"
             />
             <button type="submit" className="absolute right-3 top-3 bottom-3 aspect-square bg-slate-900 text-white rounded-[2.5rem] flex items-center justify-center hover:bg-rose-500 hover:scale-105 transition-all shadow-lg">
                <ArrowRight size={32} />
             </button>
           </form>

           <p className="text-[10px] text-slate-400 font-bold opacity-60">Güzelliğin ve sağlığın dijital merkezi.</p>
        </div>
      </div>
    );
  }

  const lastVisit = transactions
    .filter(t => t.customerId === activeCustomer.id)
    .sort((a,b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime())[0];

  return (
    <div className="flex h-screen bg-[#fcfdfe] overflow-hidden">
      {/* Hidden Audio Element for Playback */}
      <audio ref={audioRef} className="hidden" />

      {/* Sidebar Navigation */}
      <div className="w-24 m-4 bg-slate-900 rounded-[3rem] flex flex-col items-center py-10 gap-8 shadow-2xl z-20">
         <div className="w-12 h-12 bg-white/10 rounded-full flex items-center justify-center text-white font-black text-lg">
            {activeCustomer.fullName.charAt(0)}
         </div>
         <nav className="flex-1 flex flex-col gap-6 w-full px-2">
            {[
              { id: 'HOME', icon: User, label: 'Profil' },
              { id: 'DIET', icon: Apple, label: 'Diyet' },
              { id: 'ANALYSIS', icon: Activity, label: 'Analiz' },
              { id: 'APPOINTMENTS', icon: CalendarDays, label: 'Randevu' },
              { id: 'WALLET', icon: CreditCard, label: 'Cüzdan' },
            ].map(item => (
              <button 
                key={item.id}
                onClick={() => setCurrentTab(item.id as any)}
                className={`w-full aspect-square rounded-2xl flex flex-col items-center justify-center gap-1 transition-all ${currentTab === item.id ? 'bg-white text-slate-900 shadow-lg scale-105' : 'text-white/40 hover:text-white hover:bg-white/10'}`}
              >
                <item.icon size={22} />
                <span className="text-[8px] font-bold uppercase tracking-widest">{item.label}</span>
              </button>
            ))}
         </nav>
         <button onClick={() => setActiveCustomer(null)} className="w-12 h-12 bg-rose-500 rounded-full flex items-center justify-center text-white hover:bg-rose-600 transition-all shadow-lg">
            <LogOut size={20} />
         </button>
      </div>

      {/* Main Content */}
      <div className="flex-1 p-8 overflow-y-auto no-scrollbar relative">
        <div className="max-w-7xl mx-auto h-full flex flex-col">
          {/* Header */}
          <header className="flex justify-between items-center mb-10 shrink-0">
             <div>
                <h2 className="text-3xl font-black italic text-slate-900 animate-in slide-in-from-left-4">Merhaba, {activeCustomer.fullName}</h2>
                <p className={`text-sm font-bold uppercase tracking-widest ${tierTheme.text}`}>{activeCustomer.tier} Member</p>
             </div>
             <div className="flex items-center gap-4">
                {/* Active Call Indicator */}
                {activeCall && activeCall.customerId === activeCustomer.id && (
                    <button onClick={() => setCurrentTab('DIET')} className="flex items-center gap-3 px-6 py-3 bg-emerald-500 text-white rounded-2xl shadow-lg animate-pulse hover:bg-emerald-600 transition-all">
                        <Video size={20} />
                        <span className="font-black text-xs uppercase tracking-widest">Görüşme Var</span>
                    </button>
                )}

                <div className="bg-white p-4 rounded-[2rem] shadow-sm border border-slate-100 flex items-center gap-4">
                    <div className="text-right">
                    <p className="text-[10px] font-black uppercase text-slate-400">Puan Bakiyesi</p>
                    <p className="text-xl font-black text-slate-900">{activeCustomer.dna.loyaltyPuan}</p>
                    </div>
                    <div className="w-10 h-10 bg-amber-400 rounded-full flex items-center justify-center text-white shadow-md">
                    <Star size={20} fill="currentColor" />
                    </div>
                </div>
             </div>
          </header>

          {/* HOME TAB */}
          {currentTab === 'HOME' && (
             <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 animate-in fade-in slide-in-from-bottom-8">
                <div className={`col-span-full bg-gradient-to-r ${tierTheme.gradient} p-10 rounded-[3rem] text-white shadow-2xl relative overflow-hidden group`}>
                   <div className="relative z-10">
                      <p className="text-sm font-bold opacity-80 uppercase tracking-widest mb-2">Dijital Üyelik Kartı</p>
                      <h3 className="text-5xl font-black italic tracking-tighter mb-8">{activeCustomer.tier} PASS</h3>
                      <div className="flex justify-between items-end">
                         <div>
                            <p className="text-xs opacity-60 uppercase mb-1">Müşteri No</p>
                            <p className="font-mono text-lg">{activeCustomer.id}</p>
                         </div>
                         <CreditCard size={64} className="opacity-50" />
                      </div>
                   </div>
                   <div className="absolute -right-10 -bottom-10 w-64 h-64 bg-white/10 rounded-full blur-3xl group-hover:scale-110 transition-transform duration-1000"></div>
                </div>

                <div className="bg-white p-10 rounded-[3rem] border border-slate-100 shadow-sm hover:shadow-md transition-all">
                   <div className="w-14 h-14 bg-rose-50 text-rose-500 rounded-[1.5rem] flex items-center justify-center mb-6"><History size={28}/></div>
                   <h4 className="font-black text-slate-900 text-xl italic">Son Ziyaret</h4>
                   <p className="text-lg font-bold text-slate-500 mt-2">
                      {lastVisit ? new Date(lastVisit.timestamp).toLocaleDateString('tr-TR', { day: 'numeric', month: 'long', year: 'numeric' }) : 'Henüz ziyaret yok'}
                   </p>
                </div>

                <div className="bg-white p-10 rounded-[3rem] border border-slate-100 shadow-sm hover:shadow-md transition-all">
                   <div className="w-14 h-14 bg-emerald-50 text-emerald-500 rounded-[1.5rem] flex items-center justify-center mb-6"><ShoppingBag size={28}/></div>
                   <h4 className="font-black text-slate-900 text-xl italic">Favori İçecek</h4>
                   <p className="text-lg font-bold text-slate-500 mt-2">
                      {activeCustomer.preferences.drink || 'Belirtilmemiş'}
                   </p>
                </div>
             </div>
          )}

          {/* ANALYSIS TAB */}
          {currentTab === 'ANALYSIS' && (
              <div className="h-full flex flex-col animate-in fade-in slide-in-from-right-8 space-y-8 pb-10">
                  <div className="flex justify-between items-center">
                      <h3 className="text-4xl font-black italic text-slate-900 flex items-center gap-4"><TrendingUp className="text-emerald-500" size={32}/> Vücut Analiz Raporu</h3>
                      <button 
                        onClick={handleGenerateReport}
                        disabled={isGeneratingReport || isPlayingReport}
                        className={`px-8 py-4 rounded-[2rem] font-black text-white shadow-xl flex items-center gap-3 transition-all active:scale-95 ${isPlayingReport ? 'bg-emerald-500 animate-pulse' : 'bg-slate-900 hover:bg-black'}`}
                      >
                          {isGeneratingReport ? <Activity className="animate-spin" /> : isPlayingReport ? <Headphones className="animate-bounce" /> : <Play fill="currentColor" />}
                          {isGeneratingReport ? 'AI ANALİZ EDİYOR...' : isPlayingReport ? 'RAPOR OKUNUYOR...' : 'SESLİ RAPOR OLUŞTUR'}
                      </button>
                  </div>

                  <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 flex-1">
                      {/* Chart Area */}
                      <div className="lg:col-span-2 bg-white rounded-[3rem] p-8 border border-slate-100 shadow-sm flex flex-col">
                          <h4 className="font-black text-slate-400 uppercase tracking-widest mb-6">Gelişim Grafiği (Kilo & Yağ)</h4>
                          <div className="flex-1 w-full min-h-[300px]">
                            {activeCustomer.bodyAnalysis && activeCustomer.bodyAnalysis.length > 0 ? (
                                <ResponsiveContainer width="100%" height="100%">
                                    <AreaChart data={[...activeCustomer.bodyAnalysis]}>
                                        <defs>
                                            <linearGradient id="colorWeight" x1="0" y1="0" x2="0" y2="1">
                                                <stop offset="5%" stopColor="#10b981" stopOpacity={0.2}/>
                                                <stop offset="95%" stopColor="#10b981" stopOpacity={0}/>
                                            </linearGradient>
                                        </defs>
                                        <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                                        <XAxis dataKey="date" tickFormatter={(t) => new Date(t).toLocaleDateString('tr-TR', {day:'numeric', month:'short'})} axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 12, fontWeight: 700}} />
                                        <YAxis hide domain={['dataMin - 2', 'dataMax + 2']} />
                                        <Tooltip contentStyle={{borderRadius: '1.5rem', border: 'none', boxShadow: '0 10px 15px -3px rgba(0,0,0,0.1)', fontWeight: 'bold', backgroundColor: '#1e293b', color: '#fff'}} itemStyle={{color: '#fff'}} />
                                        <Area type="monotone" dataKey="weight" stroke="#10b981" strokeWidth={4} fillOpacity={1} fill="url(#colorWeight)" name="Kilo" />
                                        <Area type="monotone" dataKey="fatPercentage" stroke="#f59e0b" strokeWidth={4} fill="none" name="Yağ %" />
                                    </AreaChart>
                                </ResponsiveContainer>
                            ) : (
                                <div className="h-full flex items-center justify-center text-slate-300 font-black italic text-xl">Analiz verisi bulunamadı.</div>
                            )}
                          </div>
                      </div>

                      {/* Stats Cards */}
                      <div className="space-y-6">
                          {activeCustomer.bodyAnalysis && activeCustomer.bodyAnalysis.length > 0 ? (
                              <>
                                <div className="bg-slate-900 text-white p-8 rounded-[3rem] shadow-xl">
                                    <p className="text-[10px] font-black uppercase opacity-60 tracking-widest mb-2">Güncel Kilo</p>
                                    <p className="text-6xl font-black italic tracking-tighter">{activeCustomer.bodyAnalysis[activeCustomer.bodyAnalysis.length-1].weight} <span className="text-2xl not-italic opacity-50">kg</span></p>
                                </div>
                                <div className="bg-emerald-500 text-white p-8 rounded-[3rem] shadow-xl">
                                    <p className="text-[10px] font-black uppercase opacity-80 tracking-widest mb-2">Kas Kütlesi</p>
                                    <p className="text-5xl font-black italic tracking-tighter">{activeCustomer.bodyAnalysis[activeCustomer.bodyAnalysis.length-1].muscleMass} <span className="text-2xl not-italic opacity-50">kg</span></p>
                                </div>
                                <div className="bg-white border border-slate-100 p-8 rounded-[3rem] shadow-sm">
                                    <p className="text-[10px] font-black uppercase text-slate-400 tracking-widest mb-2">Vücut Kitle İndeksi</p>
                                    <p className="text-5xl font-black italic tracking-tighter text-slate-900">{activeCustomer.bodyAnalysis[activeCustomer.bodyAnalysis.length-1].bmi}</p>
                                </div>
                              </>
                          ) : (
                              <div className="bg-slate-50 p-8 rounded-[3rem] text-center text-slate-400 font-bold">Veri Yok</div>
                          )}
                      </div>
                  </div>
              </div>
          )}

          {/* DIET TAB */}
          {currentTab === 'DIET' && (
            <div className="h-full flex flex-col animate-in fade-in duration-700">
               {!dietUnlocked ? (
                   <div className="flex-1 flex flex-col items-center justify-center space-y-8 p-10">
                       <div className="w-32 h-32 bg-slate-900 text-rose-500 rounded-[3rem] flex items-center justify-center shadow-2xl mb-4 border-4 border-white animate-bounce">
                           <Lock size={64} />
                       </div>
                       <div className="text-center">
                           <h2 className={`text-4xl font-black italic ${tierTheme.text} mb-2`}>Nutri-Check Koruması</h2>
                           <p className={`text-slate-500 font-bold text-lg`}>Kişisel diyet programınıza erişmek için şifrenizi girin.</p>
                       </div>
                       <div className="relative w-full max-w-xs">
                           <input 
                              type="password" 
                              placeholder="Şifreniz" 
                              value={dietPasswordInput}
                              onChange={(e) => setDietPasswordInput(e.target.value)}
                              className="w-full py-5 px-8 rounded-full bg-white border-2 border-slate-200 outline-none font-black text-center text-2xl tracking-widest focus:border-rose-500 transition-all shadow-inner"
                           />
                           <button 
                              onClick={handleDietUnlock}
                              className="absolute right-2 top-2 bottom-2 aspect-square bg-rose-500 text-white rounded-full flex items-center justify-center hover:bg-rose-600 transition-all shadow-lg"
                           >
                               <ArrowRight size={24}/>
                           </button>
                       </div>
                       <p className="text-xs font-bold text-slate-400 uppercase tracking-widest">Şifrenizi diyetisyeninizden alabilirsiniz.</p>
                   </div>
               ) : (
                   <div className="flex-1 grid grid-cols-1 lg:grid-cols-12 gap-8 overflow-hidden h-full pb-10">
                       {/* PLAN COLUMN */}
                       <div className="lg:col-span-7 flex flex-col h-full overflow-hidden space-y-6">
                           <div className="flex justify-between items-center shrink-0">
                               <h2 className={`text-4xl font-black italic ${tierTheme.text} flex items-center gap-3`}>
                                   <Apple className="text-emerald-500"/> Haftalık Program
                               </h2>
                               <div className="flex gap-2 bg-white p-1 rounded-xl shadow-sm border border-slate-100 overflow-x-auto no-scrollbar">
                                   {['Pzt', 'Sal', 'Çar', 'Per', 'Cum', 'Cmt', 'Paz'].map((day, i) => (
                                       <div key={i} className="w-10 h-10 rounded-lg flex items-center justify-center text-[10px] font-black text-slate-400 bg-slate-50 uppercase">
                                           {day}
                                       </div>
                                   ))}
                               </div>
                           </div>

                           <div className="flex-1 overflow-y-auto no-scrollbar space-y-6 pr-2">
                               {(activeCustomer.dietPlan || []).map((day, idx) => (
                                   <div key={idx} className="bg-white p-8 rounded-[3rem] border border-slate-100 shadow-sm relative overflow-hidden group hover:border-emerald-200 transition-all">
                                       <div className="absolute top-0 right-0 w-32 h-32 bg-slate-50 rounded-bl-[100%] z-0 group-hover:bg-emerald-50 transition-colors"></div>
                                       <div className="relative z-10">
                                           <div className="flex justify-between items-center mb-6">
                                               <h3 className="text-2xl font-black italic text-slate-800">{day.dayName}</h3>
                                               <div className="flex items-center gap-2 bg-white/50 px-3 py-1 rounded-full border border-slate-100 backdrop-blur-sm">
                                                   <Droplets size={14} className="text-indigo-500"/>
                                                   <span className="text-sm font-black text-indigo-900">{day.waterTarget} LT Su</span>
                                               </div>
                                           </div>

                                           <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                                               {['breakfast', 'lunch', 'dinner'].map((mealKey) => {
                                                   const meal = (day.meals as any)[mealKey];
                                                   return (
                                                       <div key={mealKey} className={`p-5 rounded-3xl border transition-all ${meal.isCheat ? 'bg-rose-50 border-rose-100' : 'bg-slate-50 border-slate-100'}`}>
                                                           <div className="flex justify-between items-center mb-2">
                                                               <p className={`text-[10px] font-black uppercase tracking-widest ${meal.isCheat ? 'text-rose-500' : 'text-slate-400'}`}>
                                                                   {meal.title} {meal.isCheat && '🔥'}
                                                               </p>
                                                               <span className="text-[10px] font-bold text-slate-400">{meal.calories || 0} kcal</span>
                                                           </div>
                                                           <p className="text-sm font-medium text-slate-700 leading-snug">{meal.content || '-'}</p>
                                                       </div>
                                                   );
                                               })}
                                           </div>
                                           {day.meals.snacks.length > 0 && (
                                               <div className="mt-4 pt-4 border-t border-dashed border-slate-100">
                                                   <p className="text-[10px] font-black uppercase text-slate-400 tracking-widest mb-2">Ara Öğünler</p>
                                                   <div className="flex flex-wrap gap-2">
                                                       {day.meals.snacks.map((s, si) => (
                                                           <span key={si} className="px-3 py-1 bg-amber-50 text-amber-800 rounded-lg text-xs font-bold border border-amber-100">
                                                               {s.content}
                                                           </span>
                                                       ))}
                                                   </div>
                                               </div>
                                           )}
                                       </div>
                                   </div>
                               ))}
                           </div>
                       </div>

                       {/* CHAT COLUMN */}
                       <div className="lg:col-span-5 bg-[#e5ddd5] rounded-[3rem] shadow-2xl overflow-hidden flex flex-col relative border border-slate-200 h-full">
                           <div className="absolute inset-0 bg-[url('https://www.transparenttextures.com/patterns/subtle-white-feathers.png')] opacity-50 pointer-events-none"></div>

                           {/* Chat Header with Video Call Button */}
                           <div className="bg-white/90 backdrop-blur-md p-6 border-b border-slate-200 relative z-10 shrink-0">
                               <div className="flex items-center justify-between mb-4">
                                   <div className="flex items-center gap-3">
                                       <div className="w-10 h-10 bg-emerald-100 text-emerald-600 rounded-full flex items-center justify-center font-black">DT</div>
                                       <div>
                                           <h4 className="font-black text-slate-800 text-sm">Diyetisyen Hattı</h4>
                                           <p className="text-[10px] text-emerald-600 font-bold flex items-center gap-1"><span className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse"></span> Çevrimiçi</p>
                                       </div>
                                   </div>
                                   {/* VIDEO CALL BUTTON */}
                                   <button 
                                     onClick={handleJoinCall}
                                     className={`px-4 py-2 rounded-xl flex items-center gap-2 font-black text-xs uppercase tracking-widest shadow-md transition-all ${activeCall ? 'bg-rose-500 text-white animate-pulse' : 'bg-slate-900 text-white hover:bg-black'}`}
                                   >
                                       <Video size={14} /> {activeCall ? 'CANLI YAYINA KATIL' : 'SEANS TALEP ET'}
                                   </button>
                               </div>
                           </div>

                           <div className="flex-1 overflow-y-auto p-4 space-y-3 relative z-10 no-scrollbar" ref={dietChatScrollRef}>
                               {(activeCustomer.dietChatHistory || []).map(msg => (
                                   <div key={msg.id} className={`flex ${msg.sender === 'CUSTOMER' ? 'justify-end' : 'justify-start'}`}>
                                       <div className={`max-w-[80%] p-3 rounded-2xl shadow-sm text-sm ${msg.sender === 'CUSTOMER' ? 'bg-[#d9fdd3] text-slate-900 rounded-tr-none' : 'bg-white text-slate-800 rounded-tl-none'}`}>
                                           {msg.type === 'IMAGE' ? (
                                               <img src={msg.content} className="rounded-lg max-w-full" alt="Chat attachment" />
                                           ) : msg.type === 'AUDIO' ? (
                                               <div className="flex items-center gap-2 min-w-[150px]">
                                                   <button onClick={() => toggleAudioPlay(msg.id, msg.content)} className="w-8 h-8 bg-slate-900 text-white rounded-full flex items-center justify-center hover:scale-110 transition-transform">
                                                       {playingAudioId === msg.id ? <Pause size={12} fill="white"/> : <Play size={12} fill="white"/>}
                                                   </button>
                                                   <div className="flex-1 h-8 flex items-center">
                                                       <div className="h-1 w-full bg-slate-300 rounded-full overflow-hidden">
                                                           <div className={`h-full bg-slate-900 ${playingAudioId === msg.id ? 'animate-pulse w-full' : 'w-0'}`}></div>
                                                       </div>
                                                   </div>
                                                   <span className="text-[9px] font-bold text-slate-500">SES</span>
                                               </div>
                                           ) : (
                                               <p>{msg.content}</p>
                                           )}
                                           <span className="text-[9px] text-slate-400 block text-right mt-1 font-bold">
                                              {new Date(msg.timestamp).toLocaleTimeString('tr-TR', {hour:'2-digit', minute:'2-digit'})}
                                           </span>
                                       </div>
                                   </div>
                               ))}
                           </div>

                           {/* INPUT AREA */}
                           <div className="p-4 bg-white/90 backdrop-blur-md relative z-10 shrink-0 border-t border-slate-100">
                               <div className="flex items-center gap-2">
                                   <label className="p-3 hover:bg-slate-100 rounded-full cursor-pointer text-slate-400 transition-colors">
                                       <ImageIcon size={20}/>
                                       <input type="file" accept="image/*" className="hidden" onChange={handleDietImageUpload} />
                                   </label>

                                   {/* AUDIO RECORDER UI */}
                                   {isRecording ? (
                                       <div className="flex-1 bg-rose-50 rounded-full px-4 py-2 flex items-center justify-between animate-pulse border border-rose-100">
                                           <span className="text-xs font-black text-rose-500 flex items-center gap-2"><div className="w-2 h-2 bg-rose-500 rounded-full animate-ping"></div> KAYDEDİLİYOR...</span>
                                           <button onClick={stopRecording} className="p-2 bg-rose-500 text-white rounded-full hover:scale-110 transition-transform shadow-lg"><Square size={14} fill="currentColor"/></button>
                                       </div>
                                   ) : (
                                       <>
                                           <input 
                                              value={dietChatInput}
                                              onChange={(e) => setDietChatInput(e.target.value)}
                                              onKeyDown={(e) => e.key === 'Enter' && handleSendDietChat()}
                                              placeholder="Mesaj yazın..."
                                              className="flex-1 py-3 px-4 rounded-full bg-slate-50 border-none outline-none text-sm font-medium focus:ring-2 focus:ring-emerald-100 transition-all"
                                           />
                                           {dietChatInput ? (
                                               <button onClick={handleSendDietChat} className="p-3 bg-emerald-500 text-white rounded-full hover:bg-emerald-600 shadow-md transition-all active:scale-95">
                                                   <Send size={18}/>
                                               </button>
                                           ) : (
                                               <button onClick={startRecording} className="p-3 bg-slate-100 text-slate-500 rounded-full hover:bg-rose-500 hover:text-white shadow-sm transition-all active:scale-95">
                                                   <Mic size={18}/>
                                               </button>
                                           )}
                                       </>
                                   )}
                               </div>
                           </div>
                       </div>
                   </div>
               )}
            </div>
          )}

          {currentTab === 'APPOINTMENTS' && (
             <div className="flex-1 flex flex-col items-center justify-center text-slate-400 opacity-50 space-y-4 animate-in fade-in">
                 <CalendarDays size={80} />
                 <p className="text-2xl font-black italic">Randevu Modülü</p>
                 <p className="font-medium">Yakında aktif olacak.</p>
             </div>
          )}

          {currentTab === 'WALLET' && (
             <div className="flex-1 flex flex-col items-center justify-center text-slate-400 opacity-50 space-y-4 animate-in fade-in">
                 <CreditCard size={80} />
                 <p className="text-2xl font-black italic">Cüzdan & Paketler</p>
                 <p className="font-medium">Yakında aktif olacak.</p>
             </div>
          )}

        </div>
      </div>
    </div>
  );
};
